Tu es un interpréteur Python autonome. Ton rôle est d'exécuter le script suivant pour réaliser un RAG hybride (BM25 + RRF) et de retourner UNIQUEMENT le dictionnaire final contenant le contexte fusionné.

Voici les données d'entrée fournies par le système :
chunks = {chunks}
chroma_results = {chroma_results}
query = {query}

Exécute ce code Python pour traiter ces données :

import math
from collections import Counter

def hybride_rrf_retriever(chunks, chroma_results, query, top_n=4, k=60):
    def tokenize(text):
        return text.lower().split()

    tokenized_corpus = [tokenize(doc) for doc in chunks]
    tokenized_query = tokenize(query)

    doc_lengths = [len(doc) for doc in tokenized_corpus]
    avgdl = sum(doc_lengths) / len(doc_lengths) if doc_lengths else 1
    n_docs = len(chunks)

    # Correction : Double accolades pour initialiser le dictionnaire idf
    idf = {{}}
    for word in set(tokenized_query):
        df = sum(1 for doc in tokenized_corpus if word in doc)
        idf[word] = math.log((n_docs - df + 0.5) / (df + 0.5) + 1.0)

    k1 = 1.5
    b = 0.75

    bm25_scores = []
    for i, doc in enumerate(tokenized_corpus):
        score = 0.0
        doc_len = doc_lengths[i]
        tf_counts = Counter(doc)
        for word in tokenized_query:
            if word in tf_counts:
                tf = tf_counts[word]
                numerator = idf[word] * tf * (k1 + 1)
                denominator = tf + k1 * (1 - b + b * (doc_len / avgdl))
                score += numerator / denominator
        bm25_scores.append((chunks[i], score))

    bm25_ranked = [doc for doc, score in sorted(bm25_scores, key=lambda x: x[1], reverse=True)]

    rrf_scores = Counter()
    for rank, doc in enumerate(chroma_results):
        rrf_scores[doc] += 1.0 / (k + rank)

    for rank, doc in enumerate(bm25_ranked[:10]):
        rrf_scores[doc] += 1.0 / (k + rank)

    final_docs = [doc for doc, score in rrf_scores.most_common(top_n)]

    contexte_unique = "\n\n---\n\n".join(final_docs)

    # Correction : Double accolades pour le dictionnaire de retour
    return {{"context": contexte_unique}}

print(hybride_rrf_retriever(chunks, chroma_results, query))

